# Filter training examples
def filter_training_data(examples):
    filtered = []
    for ex in examples:
        if ex['forces_binary']:
            continue  # Skip binary-forcing examples
        if estimate_rho(ex) < 0.4:
            continue  # Skip low-ρ examples
        filtered.append(ex)
    return filtered
